import { z } from 'zod';

const AgentOutputSchema = z.object({
  status: z.enum(['pending', 'active', 'completed', 'failed']).optional(),
  task: z.string(),
}).strict(false);

const instructor = new Instructor({ client: openai });

const response = await instructor.chat.completions.create({
  model: 'gpt-4o',
  responseModel: AgentOutputSchema,
